Code.Terraform:
```hcl
# Terraform：MongoDB DMS エンドポイントで認証を有効化
resource "aws_dms_endpoint" "<example_resource_name>" {
  endpoint_id   = "<example_resource_name>"
  endpoint_type = "source"
  engine_name   = "mongodb"

  mongodb_settings {
    auth_type = "password"  # 重要：MongoDB エンドポイントの認証を有効化
  }
}
```
